/*
 * Wind-Tunnel Force Balance -- 3-channel HX711 reader + pitot (Arduino Uno)
 * -----------------------------------------------------------------------
 * Channels:
 *   liftA = FRONT TAL220 (10 kg)   DT=D2  SCK=D3   -> HX711 #1
 *   liftB = REAR  TAL220 (10 kg)   DT=D4  SCK=D5   -> HX711 #2
 *   drag  = TAS501 S-cell (200 kg) DT=D6  SCK=D7   -> HX711 #3
 *   pitot = MPXV7002DP analog out  -> A0
 *
 * Outputs (after calibration):
 *   Lift  = liftA + liftB                          [N]
 *   Pitch = (liftA - liftB) * (SPACING_M / 2.0)    [N*m]  about the MIDPOINT
 *           between the two cells. See PITCH NOTE below -- this divides by 2
 *           so the value is the TRUE moment about the centroid, NOT
 *           differential*full-spacing. Keep this consistent with C_m downstream.
 *   Drag  = drag                                   [N]
 *
 * SIGN CONVENTIONS (verify physically during calibration):
 *   - Lift positive = upward. lift = a + b only sums correctly once BOTH
 *     liftA and liftB are calibrated to read +N for UPWARD load. The cal
 *     factors below MAY legitimately be NEGATIVE (depends on bridge polarity /
 *     cantilever sense) -- but both lift channels must end up POSITIVE-up, or
 *     two opposite-sign factors silently cancel to lift ~ 0.
 *   - Pitch positive = FRONT cell loaded more than rear = NOSE-UP moment.
 *     This depends on which physical cell is wired to D2/D3 ("front").
 *     Verify: press ONLY the front of the plate -> Pitch must go POSITIVE.
 *   - Drag positive = downstream pull on the plate.
 *
 * PITCH NOTE (factor of 2): two parallel vertical reactions a distance d apart
 *   form a couple M = (F_front - F_rear) * d/2 about the midpoint between them.
 *   We use SPACING_M/2 here so "Pitch" is that true midpoint moment. If you
 *   prefer the spec's "differential * full spacing" couple referenced to one
 *   cell, drop the /2.0 -- but pick ONE definition and document it so C_m
 *   isn't off by 2x.
 *
 * Library: bogde "HX711 Arduino Library" by Bogdan Necula (install via Library
 *   Manager). Header is HX711.h; this sketch uses begin(DOUT,SCK), tare(times),
 *   set_scale(), get_value(times), get_units(times) -- all present in that lib.
 *   Confirm the AUTHOR is "bogde" (other HX711 libs have different APIs).
 *
 * Drag resolution: 200 kg cell on ~5-15 N is <1% FS -> only a handful of
 *   noise-free counts/N. Channel A is already at max gain 128 (begin default).
 *   We AVERAGE and MEDIAN-FILTER. If counts/N on drag is within a few counts of
 *   noise, swapping to a 5-10 kg cell is effectively mandatory for usable C_D.
 *
 * Calibration (no reflash needed -- send 'c' over serial to toggle modes):
 *   1) Tare with NO live load (tunnel off).
 *   2) In CAL mode the sketch prints the TARED raw value get_value(N_AVG)
 *      (i.e. raw MINUS the no-load offset -- not read()). Apply a KNOWN force
 *      along each axis (convert mass: F[N] = mass[kg] * 9.81).
 *      calFactor = (tared get_value) / F_in_Newtons   (may be negative).
 *   3) Enter CAL_LIFT_A/B/DRAG below; in RUN mode get_units() returns Newtons.
 *   The code uses ONE scale + tare offset per channel (a linear a*R fit through
 *   the tared zero). The a*R+b lab fits collapse to this because tare() removes
 *   b; if you keep a separate offset, subtract it before applying the scale.
 */

#include "HX711.h"

// ---------------- Pin map (DT, SCK) ----------------
const byte DT_LIFT_A = 2,  SCK_LIFT_A = 3;   // FRONT TAL220
const byte DT_LIFT_B = 4,  SCK_LIFT_B = 5;   // REAR  TAL220
const byte DT_DRAG   = 6,  SCK_DRAG   = 7;   // TAS501 S-cell
const byte PIN_PITOT = A0;                    // MPXV7002DP analog out

// ---------------- Geometry ----------------
// Front/rear cell spacing = pitch arm. MEASURE YOURS with calipers.
const float SPACING_M = 0.095f;   // ~95 mm between front & rear cells

// ---------------- Air / pitot constants ----------------
const float RHO_AIR   = 1.204f;   // kg/m^3 (20 C, sea level) -- adjust to site
// MPXV7002DP: Vout = 2.5 V at 0 Pa, sensitivity 1.0 V/kPa (0.001 V/Pa).
const float PITOT_V0      = 2.5f;     // V at zero differential
const float PITOT_V_PER_PA = 0.001f;  // V per Pa (from datasheet)
const float ADC_VREF      = 5.0f;     // Uno ADC reference (V)

// ---------------- Calibration factors (counts per Newton) ----------------
// Found in CAL mode (tared get_value / force_N). MAY BE NEGATIVE -- but both
// lift factors must make their channel read POSITIVE for UPWARD load.
// Placeholders -- REPLACE with your measured numbers.
float CAL_LIFT_A = 1000.0f;   // FRONT TAL220
float CAL_LIFT_B = 1000.0f;   // REAR  TAL220
float CAL_DRAG   = 100.0f;    // TAS501 (low resolution -- expect a small |value|)

// ---------------- Averaging ----------------
// uint16_t so heavy averaging on the noisy drag channel can't wrap a byte.
// NOTE: bogde get_value()/get_units() take a BYTE count (max 255). We cap N_AVG
// at 255 before calling the library so a large request can't silently wrap.
uint16_t N_AVG = 16;
byte avgTimes() { return (N_AVG > 255) ? 255 : (byte)N_AVG; }

// Mode: toggled live by sending 'c' (calibrate) / 'r' (run) over serial.
bool calibrate = false;

HX711 liftA, liftB, drag;

// ---- median of 5 quick reads to reject HX711 desync spikes ----
long medianValue(HX711 &cell) {
  long s[5];
  for (byte i = 0; i < 5; i++) s[i] = cell.get_value(avgTimes());
  for (byte i = 0; i < 4; i++)
    for (byte j = i + 1; j < 5; j++)
      if (s[j] < s[i]) { long t = s[i]; s[i] = s[j]; s[j] = t; }
  return s[2];
}
float medianUnits(HX711 &cell, float scale) {
  return (float)medianValue(cell) / scale;
}

float readQ_Pa() {
  int raw = analogRead(PIN_PITOT);
  float v  = raw * (ADC_VREF / 1023.0f);
  float pa = (v - PITOT_V0) / PITOT_V_PER_PA;   // differential pressure [Pa]
  if (pa < 0) pa = 0;                            // clamp tiny negatives
  return pa;                                     // == dynamic pressure q
}

void setup() {
  Serial.begin(115200);
  while (!Serial) { /* wait for USB serial */ }

  liftA.begin(DT_LIFT_A, SCK_LIFT_A);   // gain 128, Channel A (max gain)
  liftB.begin(DT_LIFT_B, SCK_LIFT_B);
  drag.begin (DT_DRAG,   SCK_DRAG);

  liftA.set_scale(CAL_LIFT_A);
  liftB.set_scale(CAL_LIFT_B);
  drag.set_scale (CAL_DRAG);

  Serial.println(F("Taring... keep the balance UNLOADED (tunnel off)."));
  liftA.tare(20);
  liftB.tare(20);
  drag.tare(20);
  Serial.println(F("Tare done. Send 'c' for CALIBRATE, 'r' for RUN."));
  Serial.println(F("CSV(run): millis,liftA_N,liftB_N,drag_N,Lift_N,Pitch_Nm,Drag_N,q_Pa,V_ms"));
}

void loop() {
  if (Serial.available()) {
    char c = Serial.read();
    if (c == 'c') { calibrate = true;  Serial.println(F("CAL: printing TARED raw counts (get_value). calFactor = count/force_N, force_N = kg*9.81. ch: liftA  liftB  drag")); }
    if (c == 'r') { calibrate = false; Serial.println(F("RUN mode.")); }
  }

  if (calibrate) {
    long a = medianValue(liftA);
    long b = medianValue(liftB);
    long d = medianValue(drag);
    Serial.print(a); Serial.print('\t');
    Serial.print(b); Serial.print('\t');
    Serial.println(d);
    delay(250);
    return;
  }

  // ---- Normal run: forces in Newtons (median-filtered) ----
  float a = medianUnits(liftA, CAL_LIFT_A);   // front lift [N]
  float b = medianUnits(liftB, CAL_LIFT_B);   // rear  lift [N]
  float d = medianUnits(drag,  CAL_DRAG);     // drag       [N]

  float lift  = a + b;                              // total lift  [N]
  float pitch = (a - b) * (SPACING_M / 2.0f);       // moment about MIDPOINT [N*m]
  float dragN = d;                                  // drag        [N]

  // Dynamic pressure + airspeed from the pitot.
  float q = readQ_Pa();                             // [Pa]
  float V = sqrt(2.0f * q / RHO_AIR);               // [m/s]
  // C_L, C_D = force / (q * S). S = 0.744 m^2 for the Fox; compute downstream.

  Serial.print(millis()); Serial.print(',');
  Serial.print(a, 3);     Serial.print(',');
  Serial.print(b, 3);     Serial.print(',');
  Serial.print(d, 3);     Serial.print(',');
  Serial.print(lift, 3);  Serial.print(',');
  Serial.print(pitch, 4); Serial.print(',');
  Serial.print(dragN, 3); Serial.print(',');
  Serial.print(q, 2);     Serial.print(',');
  Serial.println(V, 2);

  // Real loop rate note: median-of-5 x get_value(16) on 3 channels at 80 SPS
  // is ~5*16/80 = 1 s per channel of conversions -> well under 2 Hz, NOT 20 Hz.
  // For faster rates, drop N_AVG / median count, or read raw and average in SW.
  delay(50);
}
